CREATE VIEW IF NOT EXISTS v_profile_tag_observation_semantics AS
SELECT
  observations.subject_type,
  observations.subject_id,
  observations.subject_entity_id,
  observations.id AS observation_id,
  observations.observed_value,
  observations.observation_weight,
  observations.observation_source,
  observations.observed_at,
  observations.evidence_ref,
  observations.context_json,
  semantics.platform,
  semantics.tag_type,
  semantics.leaf_label,
  semantics.label_path,
  semantics.layer_code,
  semantics.layer_name,
  semantics.dimension_code,
  semantics.dimension_name,
  semantics.dimension_definition,
  semantics.business_strategy,
  semantics.confidence AS mapping_confidence,
  semantics.mapping_method,
  semantics.rationale AS mapping_rationale,
  observations.platform_tag_catalog_id,
  semantics.tag_value_mapping_id,
  semantics.inherited_tag_type_mapping_id,
  observations.updated_at AS observation_updated_at,
  semantics.updated_at AS mapping_updated_at
FROM profile_tag_observations observations
JOIN v_pls_platform_tag_value_semantics semantics
  ON semantics.platform_tag_catalog_id = observations.platform_tag_catalog_id
WHERE observations.status = 'active';

INSERT OR IGNORE INTO database_field_comments (
  id,
  table_name,
  field_name,
  zh_name,
  zh_description,
  business_meaning,
  example_value,
  source_ref,
  status,
  created_at,
  updated_at
)
